// Extract base64 image data from Gemini response and convert to binary
const geminiResponse = $input.first().json;
const brollData = $('SplitInBatches').first().json;

let base64Data;
let mimeType = 'image/png';
try {
  const part = geminiResponse.candidates[0].content.parts[0];
  base64Data = part.inlineData.data;
  mimeType = part.inlineData.mimeType || 'image/png';
} catch (e) {
  throw new Error(`Failed to extract image from Gemini response: ${e.message}. Response: ${JSON.stringify(geminiResponse).substring(0, 500)}`);
}

const filename = brollData.target_filename;
const binaryData = Buffer.from(base64Data, 'base64');

return {
  json: {
    ...brollData,
    filename: filename,
    generated_at: new Date().toISOString(),
    mime_type: mimeType
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      binaryData,
      filename,
      mimeType
    )
  }
};

const allItems = $('Airtable — Create Record').all();
const body = $('Webhook Trigger').first().json.body || $('Webhook Trigger').first().json;

// Count by act
const actCounts = {};
for (const item of allItems) {
  const act = item.json.act || item.json.fields?.act || 'unknown';
  actCounts[act] = (actCounts[act] || 0) + 1;
}

const summary = {
  status: 'complete',
  episode_id: body.episode_id || 'EP-001',
  act_requested: body.act || 'ALL',
  total_broll_generated: allItems.length,
  counts_by_act: actCounts,
  completed_at: new Date().toISOString()
};

return [{ json: summary }];
